import { DynamicInfo } from "@/components/ui/dynamic-info";
import { Globe, Link2, Share2 } from "lucide-react";

export default function Profile() {
  return (
    <DynamicInfo
      name="James Doe"
      role="Designer"
      avatar="https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?w=160&h=160&fit=crop"
      defaultExpanded
      socials={[
        { id: "x", icon: <Share2 size={14} />, href: "https://x.com" },
        { id: "in", icon: <Link2 size={14} />, href: "https://linkedin.com" },
        { id: "gh", icon: <Globe size={14} />, href: "https://github.com" },
      ]}
      status={{ label: "Available", color: "#22c55e" }}
    />
  );
}

