"use client";
import { useState } from "react";
import { DynamicInfo } from "@/components/ui/dynamic-info";

export default function ControlledProfile() {
  const [open, setOpen] = useState(false);
  return (
    <DynamicInfo
      name="James Doe"
      role="Designer"
      expanded={open}
      onExpandedChange={setOpen}
      status={{ label: "Available" }}
    />
  );
}

